#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Structure to represent a graph edge
typedef struct Edge {
    int src, dest, weight;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int numVertices, numEdges;
    Edge* edges;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices, int numEdges) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->numEdges = numEdges;
    graph->edges = (Edge*) malloc(numEdges * sizeof(Edge));
    return graph;
}

// Function to find the minimum time required for every node to receive the signal
int networkDelayTime(int** times, int timesSize, int* timesColSize, int n, int k) {
    // Create a graph
    Graph* graph = createGraph(n, timesSize);
    for (int i = 0; i < timesSize; i++) {
        graph->edges[i].src = times[i][0];
        graph->edges[i].dest = times[i][1];
        graph->edges[i].weight = times[i][2];
    }

    // Initialize the distance array
    int* dist = (int*) malloc((n + 1) * sizeof(int));
    for (int i = 0; i <= n; i++) {
        dist[i] = INT_MAX;
    }
    dist[k] = 0;

    // Use Dijkstra's algorithm to find the shortest path from the source node to all other nodes
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < graph->numEdges; j++) {
            int u = graph->edges[j].src;
            int v = graph->edges[j].dest;
            int w = graph->edges[j].weight;
            if (dist[u] != INT_MAX && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }

    // Find the maximum time required for every node to receive the signal
    int maxTime = 0;
    for (int i = 1; i <= n; i++) {
        if (dist[i] == INT_MAX) {
            return -1;
        }
        maxTime = (maxTime > dist[i]) ? maxTime : dist[i];
    }

    return maxTime;
}

