class Solution {
    // Function to find minimum time for every node to receive signal
    networkDelayTime(times, n, k) {
        // Create adjacency list
        const adj = Array.from({ length: n + 1 }, () => []);
        for (let [u, v, w] of times) {
            adj[u].push([v, w]);
        }

        // Initialize min-heap
        const pq = [[0, k]];

        // Initialize distance array
        const dist = Array(n + 1).fill(Infinity);
        dist[k] = 0;

        // Process nodes
        while (pq.length > 0) {
            // Sort and get node with smallest time
            pq.sort((a, b) => a[0] - b[0]);
            const [time, node] = pq.shift();

            // Traverse neighbors of current node
            for (let [nbr, wt] of adj[node]) {
                // If shorter path to neighbor is found
                if (dist[nbr] > time + wt) {
                    // Update distance
                    dist[nbr] = time + wt;
                    // Add updated time to the queue
                    pq.push([dist[nbr], nbr]);
                }
            }
        }

        // Get maximum time
        let ans = Math.max(...dist.slice(1));
        return ans === Infinity ? -1 : ans;
    }
}
